var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"으흠. 융합체들은 다 당했나 보네.","JPN":"ふうん。融合体はみんなやられたみたいね。","ENG":"Hmm... Looks like the hybriders couldn’t make it.","TWN":"嗯哼，融合體好像都不行咧？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"이래서야, 실패작. 저런 짐승들 따위로는 결국 당해내지 못해.","JPN":"わかった？　失敗作。あんな獣などでは敵うはずもないわ。","ENG":"Useless failed products. These kinds of beasts are no match for them.","TWN":" 所以才說是失敗品的嘛～結果那些畜生還是招架不住。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"풍부한 경험과 강력한 힘. 멸망에 대처하려면 야속하게도 두 마리 토끼를 다 잡아야 하는 법이라구.","JPN":"豊富な経験と強力な力。滅亡に対応するためには、くやしいけれど両方とも手にする必要があるのよね。","ENG":"Abundant experience and incredible power. Both are needed to fight against inevitable ruin.","TWN":"豐富的經驗和強大的力量，要應對滅亡，就必須二者兼備。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"구질구질하게 변명하지 마, 셰나.","JPN":"ぐずぐず言いわけしないで、シェナ。","ENG":"Don’t make such dirty excuses, Shena.","TWN":"說那麼多廢話幹嘛，世娜。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"너희가 멘탈 프린팅에 집착하는 까닭은 결국 원본이 남긴 감정 탓 아니려나?","JPN":"あなたたちがメンタル・プリンティングにこだわる理由は、結局オリジナルが残した感情のせいじゃないの？","ENG":"After all, aren’t you obsessed with Mental Printing because of the feelings left by the original?","TWN":"你們之所以如此執著於智力複印，不就是因為本體留下的情感嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭘 세상을 위해 숭고한 희생이라도 하는 척 지껄이니?","JPN":"何、世界のために崇高な犠牲を払ってやってるみたいな言い方してるのよ？","ENG":"What are you babbling on about, pretending to make a noble sacrifice for the sake of the world?","TWN":"講得一副多偉大，好像是為世界犧牲一樣？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"물론 너희 세상은 아니지.","JPN":"もちろんあなたたちの世界ではないわね。","ENG":"Not your world, of course.","TWN":"只是不是為你們的世界犧牲。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 알고 있을까? 그 <color=#ffd34c>원본</color> 년들 탓에 완성될 가망도 없는 연구에 매달려야 하는 우리 기분은?","JPN":"でもわかってるのかしら。その<color=#ffd34c>オリジナル</color>のせいで完成の見込みもない研究にすがる私たちの気持ちを。","ENG":"But can you understand how it feels? Having to stick with a hopeless research project because of those <color=#ffd34c>original</color> scumbags?","TWN":"但你知道嗎？因為<color=#ffd34c>本體</color>關係，明明沒有成功的希望，卻還是要埋首於研究。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"부질없는 짓이란 걸 알면서도 너희들이 숨을 쉬듯 멘탈 프린팅에만 매달리는 기분을?","JPN":"儚いとわかっていてもあなたたちが呼吸をするように、ただメンタル・プリンティングだけにすがる気持ちを。","ENG":"How it feels, when even though you know it’s useless, you still hold onto Mental Printing as though you needed it as much as you need to breathe?","TWN":"明知道是徒勞無功，卻依舊只能執著於智力複印的心情你懂嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"어차피 실패작인 네가 이해할 수 있는 날은 오지 않겠지만!","JPN":"どうせ失敗作のあなたが理解できる日は来ないでしょうけど！","ENG":"In any case you will never be able to understand, failed product!","TWN":"像你這種失敗品是永遠都不會懂的！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……궁지에 몰리니 동정심이라도 사려고?","JPN":"……追いつめられて哀れを誘うつもり？","ENG":"...You expect me to feel sorry for you?","TWN":"……現在是走投無路，所以想改用苦肉計嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"끝까지 역겹네. 그런 가증스러운 짓을 너희 상대하면서 한두 번 본 줄 알아?","JPN":"最後まで吐き気がするね。あなたたちを相手する間、その憎たらしい演技は飽きるほど見て来たの。","ENG":"You disgust me. Do you know how many times I’ve seen you do such deceitful things ever since I started opposing you?","TWN":"到現在還在死鴨子嘴硬，你以為我不知道你們幹的那些壞事嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"아차. 들켰나.","JPN":"まあ。バレた？","ENG":"Whoops. You got me.","TWN":"哎呀，被發現啦？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Haa…","TWN":"呼……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르, 셰나의 반응은?","JPN":"イェゴール、シェナの反応は？","ENG":"Yegor, Shena’s signal response?","TWN":"伊高爾，世娜的反應呢？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"반경 40km 내에서 감지되지 않습니다.","JPN":"半径40km内では感知されていません。","ENG":"It is not detected within a 40km radius.","TWN":"在半徑40km內都沒有感應到。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"관리국 정찰위성의 관측 결과……. 손상이 심해 이면세계로 퇴거된 모양입니다.","JPN":"管理局の偵察衛星の観測結果……ひどく損傷し、裏世界へと退去したようです。","ENG":"According to the Administration’s surveillance satellite... It seems the damage was so severe she was displaced to Counterside.","TWN":"根據管理局偵查衛星的偵測結果……似乎是受損太嚴重，暫時退到異界的樣子。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 어서 움직이자.","JPN":"よし。早速動きましょう。","ENG":"Alright. Let’s move.","TWN":"很好！立刻移動！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"팔에 상처가 큽니다. 응급 처치라도 하시죠.","JPN":"腕の怪我が深いです。応急処置でもしてください。","ENG":"The wound on your arm is severe. It requires immediate medical attention.","TWN":"副戰隊長，你手上的傷很嚴重，先處理一下傷口吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"됐어. 내 몸 상한 것보다 다른 애들 보급품이나 챙겨 줘.","JPN":"いいよ。私より、他の子どもたちにちゃんと補給品を配ってあげて。","ENG":"It’s fine. Don’t worry about me, make sure the other kids are well supplied.","TWN":"不需要，不用擔心我的傷，先去預備其他人的補給品吧。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"팔을 뺏어가겠다고 하더니 끝까지 팔만 노리네. 집요하긴.","JPN":"腕をもらうとは言ってたけど、最後まで腕だけを狙ってくるのね。しつこいったら。","ENG":"She said she’d get my arm, and she’s been aiming for it the whole time. She’s quite persistent.","TWN":"她說要奪走我的手臂，還真的就只攻擊手臂呢，真是固執。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"부전대장님! 제 말 좀 들어 보세요!","JPN":"副戦隊長！　ちょっと聞いてください！","ENG":"Deputy Commander! Listen to me!","TWN":"副戰隊長！我有話要跟你說！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그러니까……. 레버넌트가 선내에서 이탈했다고?","JPN":"だから……レヴナントが船内から離脱したって？","ENG":"You’re saying... Revenant left the ship?","TWN":"你說……亡靈不在艙內？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"죄송해요. 제가 붙잡지 못했어요.","JPN":"すみません。私は止められませんでした。","ENG":"I’m sorry. I couldn’t stop her.","TWN":"抱歉，我沒能攔住她。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아니. 그 사람 실력은 지난번에 봤으니 이해해.","JPN":"いいのよ。あの人の実力はこの前見たからわかる。","ENG":"It’s fine. I saw how skilled she was last time, so I understand.","TWN":"沒事，上次就有見識到她的本事，我懂的。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"조금 더 필사적으로 붙잡아 줬으면 좋았겠지만.","JPN":"もうちょっと必死に止めてほしかったけど。","ENG":"It would have been nice if you had tried harder to stop her, but whatever.","TWN":"只是你應該更努力攔住她的。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"모네카, 정부군의 동향은?","JPN":"モネカ、政府軍の動向は？","ENG":"Moneka, report the movements of the government army.","TWN":"莫奈卡，政府軍現在的動向呢？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"이렇다 할 움직임은 보이지 않습니다. 다만 보안국 쪽이 심상치 않아요.","JPN":"これと言った動きはありません。ただ保安局の方が怪しいです。","ENG":"I am not detecting any significant movement. But the National Security is acting unusual.","TWN":"目前沒看到，不過安全局那邊不太對勁。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"전용 회선의 데이터를 분석한 바에 따르면…….","JPN":"専用回線のデータを分析してみたところ……","ENG":"According to the data retrieved from analyzing their exclusive line...","TWN":"根據專屬線路的資料分析結果……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"폭발……? 포대 방향입니다!","JPN":"爆発……？　砲台からです！","ENG":"Explosion...? The direction of the turret!","TWN":"爆炸……？是砲台方向！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"칫…….","JPN":"ちっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"예고르! 둘로 나눈다!","JPN":"イェゴール、二手に分かれる！","ENG":"Yegor! Split in two!","TWN":"伊高爾！分二隊！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"커헉……! 쿨럭, 헉……! 허억……!","JPN":"がはっ……！　ゴホッ、はっ……！　はぁ……！","ENG":"Aack...! *Cough...!* *Huff...!*","TWN":"咳咳……！咳咳……咳咳咳……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"빌어먹을……. 이런 게 어딨어……. 고작, 고작 한 명한테…….","JPN":"くそ……これはないだろ……たった、たった一人に……","ENG":"Damn it... How can this be? It’s just one person...","TWN":"該死……這怎麼可能……她…她才一個人……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇게 억울해하지 마.","JPN":"そんなにくやしがらないで。","ENG":"No need to be so upset.","TWN":"不要一副可憐兮兮的樣子。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"도련님 이름이…….","JPN":"坊ちゃんの名前って……","ENG":"Your name...","TWN":"少爺的名字是……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……뭐였더라. 피를 많이 흘려서 그런지 머리가 멍하네.","JPN":"……なんだっけ？　血を流しすぎて頭がボーっとするね。","ENG":"...What was it again? I’ve lost a lot of blood so my memory is a little iffy.","TWN":"……是什麼？是因為流太多血嗎？害我腦袋有點不清楚。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"뭐야……. 너도, 죽어가는 거냐…….","JPN":"なんだ……お前も、死にかけてんのかよ……","ENG":"What... Are you dying, too...?","TWN":"搞什麼……你也傷得不輕嘛……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"등신 같이 혼자 쳐들어오길래……. 믿는 구석이라도 있는 줄 알았더니…….","JPN":"バカみたいに一人で攻め込んでくるから……何かあんのかなと思ったら……","ENG":"You came alone like a fool... I thought you had some sort of special plan...","TWN":"像瘋子似的單槍匹馬闖進來……我還以為是有什麼靠山咧……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러게. 급소는 맞아 본 적 없었는데……. 상상 이상으로 아프네.","JPN":"そうね。急所に当たったことはなかったけど……想像以上に痛いね。","ENG":"Yeah, well. My vitals have never been hit before... It hurts way more than I’d thought it would.","TWN":"真是的，我還是第一次被打中要害……比想像中還痛呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……왜 그랬어. 그냥 살지.","JPN":"……なんでだったの？　そのまま生きていけばよかったじゃない。","ENG":"...Why did you have to do that? You could’ve just lived on.","TWN":"……我幹嘛自討苦吃，活著不好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"헤, 헤헤……. 개수작 부리지 마…….","JPN":"へ、へへ……ふざけんなよ……","ENG":"Heh, heh heh... Don’t be ridiculous...","TWN":"嘿嘿嘿……少跟我耍嘴皮子……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"그래도 다른 연놈들처럼……. 싸질러 놓고 튀진 않았는데…….","JPN":"それでも他の奴らのように……産んでおいて逃げはしなかったんだ……","ENG":"Unlike most... My dad didn’t just disappear from my life. Unlike so many trash deadbeat dads in this city.","TWN":"至少他沒像其他人渣一樣……只負責生，不負責養……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGUE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROGUE_EXTRA_NULL_NULL","text":{"KOREA":"원수는…… 갚아…… 야…….","JPN":"仇は……取ら……ねえと……","ENG":"Must... Get... Revenge...","TWN":"我……我要……報……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……도련님?","JPN":"……坊ちゃん？","ENG":"...Hey?","TWN":"……少爺？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"전화…….","JPN":"電話……","ENG":"A call...","TWN":"有電話……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아, 놓쳐 버렸네…….","JPN":"あ、切れちゃった……","ENG":"Ah, dropped it...","TWN":"啊，沒拿好……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"국장님 전화면……. 받아야…….","JPN":"局長の電話なら……出ないと……","ENG":"Have to pick up... Chief’s call...","TWN":"部長打來的……我一定……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"윗분들께 이야기를 듣고 깜짝 놀랐어, 레아.","JPN":"上から話を聞いてびっくりしたわ、レア。","ENG":"What I heard was quite surprising, Leah.","TWN":"聽到上頭跟我說的話，我很吃驚呢，蕾亞。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"사적인 감정으로 몸을 던지다니 이제 정말 인간이나 다름없어졌네.","JPN":"私情で身を投げるなんて、もう本当に人間同様ね。","ENG":"Due to personal feelings, throwing your entire body into something, there really is no difference between you and a real human being.","TWN":"竟然因為個人情感因素而奮不顧身，你現在真的和人類沒有兩樣呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"인간에게 관심도 없던 분이 인간에 대해 알게 되다니…….","JPN":"人間に何の興味もなかった方が、人間を理解するようになるなんて……","ENG":"For someone who never cared about humans to get to know them in such a way...","TWN":"明明對人類沒興趣，卻開始理解人類……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"꿈을 꾸고 있는 당신이 조금은 샘나기 시작했어요. 지휘자님.\xA0","JPN":"夢を見ているあなたがちょっとはうらやましくなりました。マエストロ。\xA0","ENG":"I’m starting to get a little jealous of this dream of yours, Maestra Nequitia.","TWN":"我開始有點忌妒在睡夢中的你囉，指揮家。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};